function ModelPlot:GetPlotCfg(refId)
    local ref = GameTable.StorylinePlotRef[refId]
    if not ref then
        printInfoNR2("缺少配置", string.format("GameTable.StorylinePlotRef, refId = %s",refId or "nil"))
    end
    return ref
end

function ModelPlot:GetPara(key)
    local parseFunc = self._parseFuncMap[key]
    local value =  self:GetParaConfigValueImpl(ModelPlot.StorylineConfigRef,key,parseFunc)
    return value
end

function ModelPlot:TriggerPlot(type,para,endCall)
    if PRODUCT_G_VER ~= 0 then --提审屏蔽所有剧情
        if endCall then
            endCall()
        end
        return
    end

    local plot,storyId,newbieId, key = self:GetTriggerStoryId(type,para)

    local isTrigger = false
    if plot and plot>0 then
        isTrigger = true
        self:StoryChangeReq(key)
        self:RemoveCompletePlot({key})
        self:StartPlotAndCallback(plot,endCall)
    elseif storyId and storyId> 0 then
        gLGpManager:FindStoryCopyGp():StartStory(storyId)
    elseif newbieId and newbieId > 0 then
        gLGpManager:FindNewbieGp():StartNewbie(newbieId, true, function()
            FireEvent(EventNames.ON_UISHOW_NEWBIE_FINISHED, newbieId)
        end)
    end

    if not isTrigger then
        if endCall then
            endCall()
        end
    end
end

function ModelPlot:GetTriggerStoryId(type,para)
    local plot = nil
    local storyId = nil
    local triggerKey = nil
    local newbieId = nil
    for k,v in pairs(self._conditions) do
        if v.para.type == tostring(type) and v.para.para == tostring(para) then
            plot = v.plotId
            storyId = v.storyId
            newbieId = v.newbieId
            triggerKey = k
            break
        end
    end

    return plot,storyId,newbieId,triggerKey
end


function ModelPlot:NodeTriggerPlot(node)
    if not node then
        return false
    end

    for k,v in pairs(self._conditions) do
        if tonumber(v.para.type) == 3 then
            local num = tonumber(v.para.para)
            if num and num == node then
                return true
            end
        end

    end

    return false
end

function ModelPlot:RemoveCompletePlot(list)
    for k,v in ipairs(list) do
        self._conditions[v] = nil
    end
end

function ModelPlot:StartPlotAndCallback(plot, plotCallback,isGuide, heroEffectRef,otherData)
    local isInGuide = gModelGuide:IsInGuide()
    if isInGuide and not isGuide then
        printErrorN("指引期间不能插入其他剧情 "..plot)
        if plotCallback then
            plotCallback()
        end
        return
    end

    if self._plotCallback then
        if LOG_INFO_ENABLED then
            print("last end call not executed")
        end
    end

    self._plotCallback = plotCallback

    self:StartPlot(plot, heroEffectRef,nil,otherData)
end

function ModelPlot:StartPlot(plot, heroEffectRef,closeFunc,otherData)
    if PRODUCT_G_VER ~= 0 then --提审屏蔽剧情
        self:OnPlotComplete(true)
        return
    end

    self._executingPlot = plot
    --print(string.format("self._executingPlot %s",plot))

    local cfg = self:GetPlotCfg(plot)
    if not cfg then
        printErrorN(string.format("not plot cfg id %s ",plot))
        self:OnPlotComplete(true)
        return
    end
    --if cfg.type == 2 then
    --    GF.CloseWndByName("UIPt")
    GF.OpenUIGue("UIPtTwo",{plotId = plot, heroEffectRef = heroEffectRef,closeFunc = closeFunc,otherData=otherData})
    --else
    --    GF.CloseWndByName("UIPtTwo")
    --    GF.OpenUIGue("UIPt",{plotId = plot})
    --end


end

function ModelPlot:StartPlotPara(para)
    local plot= para.plot
    local plotCallback = para.endCall
    local closeFunc = para.closeFunc

    self._plotCallback = plotCallback
    self._executingPlot = plot

    local cfg = self:GetPlotCfg(plot)
    if not cfg then
        printErrorN(string.format("not plot cfg id %s ",plot))
        self:OnPlotComplete(true)
        return
    end

    GF.OpenUIGue("UIPtTwo",{plotId = plot,closeFunc = closeFunc})
end

