function ModelPlot:OnClickSkip(plotId,closeFunc)
    local endPlot,isSel = self:GetSkipEndPlot(plotId)
    if isSel then
        if self._executingPlot == endPlot then
            return
        end
        self:StartPlot(endPlot,nil,closeFunc)
    else
        self._executingPlot = endPlot
        self:OnPlotComplete(true)
    end

end

function ModelPlot:NextPlot(closeFunc)
    local cur = GameTable.StorylinePlotRef[self._executingPlot]
    if not cur then
        self:OnPlotComplete()
        return
    end
    local nextPlot = cur.next
    if nextPlot == self._executingPlot then
        self:OnPlotComplete(true)
        LogError("loop plot "..nextPlot)
        return
    end

    if nextPlot>0 then
        self:StartPlot(nextPlot,nil,closeFunc)
    else
        self:OnPlotComplete(true)
    end
end

function ModelPlot:NextSelectPlot(plotId,closeFunc)
    if plotId>0 then
        self:StartPlot(plotId,nil,closeFunc)
    else
        self:OnPlotComplete(true)
    end
end

function ModelPlot:StopPlot()
    self._executingPlot = nil
    self._plotCallback = nil
end

function ModelPlot:OnPlotComplete(sendEvent)
    GF.CloseWndByName("UIPtTwo")
    GF.CloseWndByName("UIPt")

    --print(string.format("OnPlotComplete %s",self._executingPlot))

    local curPlot = self._executingPlot
    if not curPlot then
        return
    end
    local endPlot = self:GetEndPlot(curPlot)

    self._executingPlot = nil
    if sendEvent then
        FireEvent(EventNames.ON_PLOT_COMPLETE,endPlot)
    end

    local callBack = self._plotCallback
    self._plotCallback = nil
    if callBack then
        callBack(endPlot)
    end

end


function ModelPlot:GetEndPlot(plot)
    local curPlotId = plot
    local records ={}
    while true  do
        local cfg = GameTable.StorylinePlotRef[curPlotId]
        if not cfg then
            break
        end
        records[curPlotId] = true
        local next = cfg.next
        if next == 0 then
            break
        end
        if next == -1 then
            next = cfg.next1
            if next == 0 then
                next = cfg.next2
            end
            if next == 0 then
                break
            end
        end
        curPlotId = next
        if records[curPlotId] then
            break
        end
    end

    return curPlotId
end

function ModelPlot:GetSelectList(refId)
    local data = self._selections[refId]
    if data then
        return data
    end
    local ref = GameTable.StorylinePlotRef[refId]
    if not ref then
        printErrorN(string.format("no cfg %s",refId))
        return
    end

    local selectList = {}
    local buttonStr = ref.button1
    buttonStr = ccLngText(buttonStr)
    if not string.isempty(buttonStr) then
        local next = ref.next1
        local data =
        {
            buttonStr = buttonStr,
            next = next,
        }
        table.insert(selectList,data)

    end


    buttonStr = ref.button2
    buttonStr = ccLngText(buttonStr)
    if not string.isempty(buttonStr) then
        local next = ref.next2
        local data =
        {
            buttonStr = buttonStr,
            next = next,
        }
        table.insert(selectList,data)
    end

    if #selectList>0 then
        self._selections[refId] = selectList
    end

    return self._selections[refId]
end

