function ModelPlot:GetStoryEventSimpleList(refId)
    local cfg = self:GetStorySceneRef(refId)
    if not cfg then return end

    local eventStr = cfg.event
    local eventList = LxDataHelper.ParseNumber_Sign(eventStr,'|')
    local list = {}
    for k,v in ipairs(eventList) do
        local eventCfg = self:GetStoryEventRef(v)
        if eventCfg then
            table.insert(list,{
                eventId = v,
                startTime = eventCfg.beginTime,
                endTime = eventCfg.endTime,
                eventType = eventCfg.eventType
            })
        else
            printErrorN("not storyevent id "..v)
        end
    end
    return list
end

