function ModelPlot:ParseConfig()
    self._isParseConfig = true

    self._conditions={}

    local ref = self:GetStoryTriggerRef()
    for k,v in pairs(ref) do
        local plot = v.plot
        local story = v.story
        local newbieId = v.newbieId
        if plot>0 or story>0 or newbieId > 0 then
            local data =
            {
                plotId = plot,
                storyId = story,
                newbieId = newbieId,
                para = self:ParseCondition(v.condition)
            }
            self._conditions[k] = data
        end

    end


end

function ModelPlot:ParseCondition(str)
    if string.isempty(str) then
        return {}
    end
    local s,e,cap1,cap2 = string.find(str,"(%w+)=(%w+)")
    if not cap1 or not cap2 then
        printInfoN("ModelPlot:ParseCondition, wrong cfg"..str)
    end
    local t = {
        type = cap1,
        para = cap2
    }

    return t
end

function ModelPlot:IsInPlot()
    return self._executingPlot~= nil
end


