function ModelPlot:CheckRestartStory()
    local startType =self._startStoryType
    if startType == ModelPlot.START_TYPE_0 then
        local step = self:GetSceneResetStep(self._lastSceneId)
        if step > 0 then
            return true,step,startType
        end
    elseif startType == ModelPlot.START_TYPE_1 then
        local step = self:GetStoryResetStep(self._lastSceneId)
        if step > 0 then
            return true,step,startType
        end
    elseif startType == ModelPlot.START_TYPE_2 then
        local step = self:GetStoryNewbieResetStep(self._lastSceneId)
        if step > 0 then
            return true,step,startType
        end
    end

end

function ModelPlot:TryRestartStory(type,step)
    if type == ModelPlot.START_TYPE_0 then
        gLGpManager:FindStoryCopyGp():StartStory(step)
    elseif type == ModelPlot.START_TYPE_1 then
        GF.OpenWnd("UICartront",{stepId= step,isStartStory = true})
    elseif type == ModelPlot.START_TYPE_2 then
        gLGpManager:FindNewbieGp():StartNewbie(step)
    end
end

