---开场剧情播完了
function ModelPlot:IsStartPlayEnded()

    --if not self:IsPrologueOpen() then
    --    return true
    --end

    if self._startStoryType == ModelPlot.START_TYPE_0 then
        local step = self:GetSceneResetStep(self._lastSceneId)
        if step<=0 then
            return true
        end
    elseif self._startStoryType == ModelPlot.START_TYPE_1 then
        local step = self:GetStoryResetStep(self._lastSceneId)
        if step <=0 then
            return true
        end
    elseif self._startStoryType == ModelPlot.START_TYPE_2 then
        local step = self:GetStoryNewbieResetStep(self._lastSceneId)
        if step <=0 then
            return true
        end
    end

    return false
end


