function ModelPlot:GetTeachingRefList()
    local list = self:GetModelConfig(ModelPlot.SupportTeachingRef)
    local dataList = {}
    for k,v in pairs(list) do
        if v.sort > 0 then
            table.insert(dataList,v)
        end
    end

    table.sort(dataList,function (a,b)
        return a.sort < b.sort
    end)
    return dataList
end

