function ModelPlot:GMSkip()

    if self:IsStartPlayEnded() or not self:IsStartPlayed() then
        return
    end

    local startType = self:GetStartPlotType()
    if startType == ModelPlot.START_TYPE_0 then
        local isRunning = gLGpManager:FindStoryCopyGp():IsRunning()
        if not isRunning then
            return
        end

        gLGpManager:FindStoryCopyGp():StopStory()
        GF.CloseWndByName("UISy")
    elseif startType == ModelPlot.START_TYPE_2 then
        local isRunning = gLGpManager:FindNewbieGp():IsRunning()
        if not isRunning then
            return
        end
        gLGpManager:FindNewbieGp():StopStory()
        GF.CloseWndByName("UINeie")
    end

    if gModelFunctionOpen:CheckIsOpened(10000000) then
        gModelFunctionOpen:Jump(10000000)
    else
        gModelFunctionOpen:Jump(10200000)
    end
    gModelFunctionOpen:DebugTag()

    --self:OnSceneSystemLookReq(0)

    self:RecordStep(startType,0)

    if startType == ModelPlot.START_TYPE_2 then
        GF.CloseWndByName("UIPerCreateName")
        if gModelPlayer:IsNoName() then
            GF.OpenWnd("UIPerCreateName", {isNew = true, FromNoName=true})
        end
    end
end

--跳过新手剧情和指引
function ModelPlot:JumpNewPlot()
    --gModelGeneral:SetFirstStoryNull()
    --GF.ChangeMap("LCityMap")
    --gLGpManager:FindStoryCopyGp():StopStory()
    GF.CloseWndByName("UISy")
    GF.CloseWndByName("UINeie")

    FireEvent(EventNames.REFRESH_FUNCTION_STATE)
    --设置默认阵型
    local combatType = LCombatTypeConst.COMBAT_MAIN
    if not gModelFormation:IsAnyValidHeroInFormation(combatType) or gModelInstance:IsAutoOneKeyUp() then
        gModelBattle:DoOneKeyMainFormation()
    end

    if gModelFunctionOpen:CheckIsOpened(10000000) then
        gModelFunctionOpen:Jump(10000000)
    else
        gModelFunctionOpen:Jump(10200000)
    end
end

function ModelPlot:CheckIsOpenCommonTips(tipsRef)
    if tipsRef == 170011 then
        -- todo 先暂时 默认屏蔽掉新手
        if true then return true end 

        if self._isJumpNewPlot == nil then printInfoN2("cjh------","is nil -------") end
        
        --滚服玩家跳过前期剧情的确认弹窗
        if self._isJumpNewPlot ~= nil then
            if self._isJumpNewPlot then
                --跳过新手剧情
                return true
            else
                --不跳过新手剧情  
                return false
       
            end
        elseif GF.FindFirstWndByName("UIOrdinTip") then --弹窗正打开中
            return true
        elseif gModelGuide:IsMeetJumpNewPlot() then --满足跳过条件的老玩家
            local func = function()
                gModelGuide:GuideJumpReq(1,1)
                self._isJumpNewPlot = true
            end

            local cancelFunc = function()
                gModelGuide:GuideJumpReq(1,0)
                self._isJumpNewPlot = false
            end

            local refId = tonumber(tipsRef)
            gModelGeneral:OpenUIOrdinTips({refId = refId,func = func, leftFunc = cancelFunc, closeFunc = cancelFunc}, true, true)
            return true
        else
            --满足跳过条件的
            gModelGuide:GuideJumpReq()
        end
    end

    return false
end

