function ModelPlot:PlayPlotList(plotList)

    local func = nil
    func= function()
        local plot = table.remove(plotList,1)
        if not plot then
            return
        end

        self:StartPlotAndCallback(plot,func)
    end

    func()
end

function ModelPlot:GetRandomClickPlot(eventId)
    local parseFunc = function(value)
        return LxDataHelper.ParseNumber_Sign(value,',')
    end
    local value = self:GetConfigValueImpl(ModelPlot.CityMapEventRef,eventId,"triggerTxt",parseFunc)
    if not value then
        return
    end

    local cnt = #value
    if cnt == 0 then
        return
    end

    if cnt == 1 then
        return value[1]
    end

    local index = math.random(1,cnt)
    return value[index]
end

function ModelPlot:HasNextPlot(plotId)
    local cfg = GameTable.StorylinePlotRef[plotId]
    if not cfg then
        return false
    end
    local next = cfg.next
    if next == 0 then
        return false
    end

    return true
end

