function ModelPlot:RandomStartPlot()

    if self._startData then
        return self._startData
    end

    local ref = self:GetModelConfig(ModelPlot.NewPlayerGuidePrologueRef)

    local dataList = self:GetPlotWeightCfg()

    local totalWeight = 0
    for k,v in ipairs(dataList) do
        totalWeight = totalWeight + v.weight
    end

    local ran = math.random(1,totalWeight)

    local refId = nil
    local weightCnt = 0
    for k,v in ipairs(dataList) do
        weightCnt = weightCnt + v.weight
        if ran <= weightCnt then
            refId = v.refId
            break
        end

    end

    printInfoN2("随机剧情","剧情配置 ".. refId)

    local data = ref[refId]
    if not data then
        printErrorN("miss GuidePrologueRef refId "..refId)
    end

    self._startData = data
    return data
end

function ModelPlot:GetPlotWeightCfg()

    local dataList = gModelActivity:GetPlotWeightCfg()
    if dataList then
        printInfoNR(dataList)
        return dataList
    end

    local ref = self:GetModelConfig(ModelPlot.NewPlayerGuidePrologueRef)

    dataList = {}
    for k,v in pairs(ref) do
        table.insert(dataList,v)
    end

    table.sort(dataList,function (a,b)
        return a.refId < b.refId
    end)

    return dataList
end

