function ModelPlot:RecordStep(type,refId)

    if self._startStoryType == ModelPlot.START_TYPE_0 then
        local storyType = self:GetStoryRefType(refId)
        if storyType and storyType ~= 10 then
            return
        end
    end

    local pb = LProtoHelper.CreateProto(LProtoIds.SceneSystemLookReq)
    pb.sceneId = refId
    pb.type = type

    self._startStoryType = type
    self._lastSceneId = refId
    SendMessage(pb,LProtoIds.SceneSystemLookReq)

    if type == ModelPlot.START_TYPE_2 then return end
    gLxTKData:OnPreStoryStep(refId,type)
end


function ModelPlot:GetStoryNewbieResetStep(refId)
    local ref = GameTable.StoryNewbieRef[refId]
    if not ref then
        return 0
    end
    return ref.resetId
end

function ModelPlot:GetStoryResetStep(refId)
    local ref = GameTable.StoryStepRef[refId]
    if not ref then
        return 0
    end

    return ref.resetId
end

function ModelPlot:GetSceneResetStep(refId)
    local cfg = self:GetStorySceneRef(refId)
    if not cfg then return 0 end

    local resetId = cfg.resetId
    return resetId
end

function ModelPlot:GetStoryGuideType()
    local guideType = 1
    local beginType = self._startStoryType
    if beginType < 0 then
        local data = self:RandomStartPlot()
        guideType = data.type
    else
        local ref = self:GetModelConfig(ModelPlot.NewPlayerGuidePrologueRef)
        for k,v in pairs(ref) do
            if v.beginType == beginType then
                guideType = v.type
                break
            end
        end
    end


    return guideType or 1
end


function ModelPlot:GetLastStepId(refId)
    local record = {}
    local tempId = refId
    while true do
        local ref =  GameTable.StoryStepRef[tempId]
        if not ref then
            break
        end
        if ref.nextStep == 0 then
            break
        end
        if record[tempId] then
            LogError("loop step id ".. tempId);
            break
        end
        record[tempId] = true

        tempId = ref.nextStep
    end

    return tempId
end

function ModelPlot:GetRolePlotText(refId)
    local cfg = self:GetPlotCfg(refId)
    if not cfg then
        return ""
    end

    local paint = cfg.paint
    if paint == "1" then
        local roleSex = gModelPlayer:GetPlayerSex()
        if roleSex ~= 1 then
            --女描述
            local girlTxt 	= cfg.girlTxt
            if not string.isempty(girlTxt) then
                LogError("返回的女描述?")
                return ccLngText(girlTxt)
            end
        end
    end

    --男描述
    return ccLngText(cfg.txt)
end

function ModelPlot:GetSkipEndPlot(plotId)
    local curPlotId = plotId
    local isSel = false
    local records ={}
    while true  do
        local cfg = GameTable.StorylinePlotRef[curPlotId]
        if not cfg then
            break
        end
        records[curPlotId] = true
        if cfg.next1 > 0 then
            isSel = true
            break
        end

        if cfg.next2 > 0 then
            isSel = true
            break
        end
        local next = cfg.next
        if next == 0 then
            break
        end
        curPlotId = next

        if records[curPlotId] then
            break
        end
    end

    return curPlotId,isSel
end

